# Read the CSV file
csv_path = r'c:\Users\matta\OneDrive\Desktop\ecommerce\ecommerce\data\products.csv'

# Read existing data
with open(csv_path, 'r', encoding='utf-8') as f:
    reader = csv.DictReader(f)
    rows = list(reader)

# Add new products
for product in products_data:
    rows.append(product)

# Write back to CSV
with open(csv_path, 'w', newline='', encoding='utf-8') as f:
    writer = csv.DictWriter(f, fieldnames=[
        'product_id', 'product_family_id', 'name', 'brand', 'category', 'subcategory',
        'description', 'price', 'variant_type', 'variant_value', 'variant_label',
        'is_default', 'thumb_image_url', 'hero_image_url', 'image_url'
    ])
    writer.writeheader()
    writer.writerows(rows)

print(f"Successfully added {len(products_data)} products to products.csv")
print("Total products now:", len(rows))
